var e=JSON.parse(`[{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"꿈과 희망과 환상과 모험과 신비와 쾌락의 <color=#ffd34c>헤이븐 랜드</color>!","JPN":"夢と希望と幻と冒険と神秘と快楽の<color=#ffd34c>ヘイブンランド</color>！","ENG":"<color=#ffd34c>Havenland</color>! Your hopes and dreams, fantasies and adventures, mysteries and pleasures await you here!","TWN":"充滿夢想、希望、奇幻、冒險、神秘和歡樂的<color=#ffd34c>天堂樂園</color>！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"모든 감각을 만족시킬 만한 지상, 아니 상공 최대의 차원 함선!!","JPN":"すべての感覚を満足させてくれる地上、いや、上空最大の次元艦船！！","ENG":"The largest dimensional ship on the planet─ No! Up in the air! Where you can indulge all of your senses!","TWN":"滿足你所有感官的地上…，不，是空中最大次元艦船！！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"모두가 그곳에서 일하길 꿈꿔.","JPN":"みんながそこで働く夢を見るんだ。","ENG":"Everyone dreams of working there.","TWN":"所有人都夢想在這個地方工作。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"특히 <color=#ffd34c>이곳</color> 아이들이라면 누구나 꿈꿔 왔지.","JPN":"特に<color=#ffd34c>ここ</color>の子どもたちならみんなそう。","ENG":"Especially if you’re a child who grew up <color=#ffd34c>here</color>.","TWN":"尤其是<color=#ffd34c>這個地方</color>的孩子，都曾經有過這樣的夢想。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"나처럼.","JPN":"私のように。","ENG":"Just like me.","TWN":"就像我一樣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"꿈은…… 깨어나면 그저 꿈일 뿐인데.","JPN":"夢は……覚めてしまえばただの夢に過ぎないのにね。","ENG":"But dreams... are just that. Dreams.","TWN":"但夢醒後……終究是一場夢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哀……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"품목이 안 맞아, 안 맞는다고……!","JPN":"品目が合わない、合わないんだよ……！","ENG":"The numbers don’t match! Geez...!","TWN":"品項根本不對，都對不起來……！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이 놈의 향초는 보급 품목에 대체 왜 들어 있는 거야? 개수 세느라 헷갈려 죽겠네!","JPN":"この香草はなんで補給品に入ってるわけ？　数えるのに紛らわしいったら！","ENG":"Who the hell puts scented candles in the supply list? How am I supposed to keep count of all of them?!","TWN":"幹嘛要把這傢伙的煙草放進補給品項裡啦！害我算得頭昏腦脹的！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그냥 때려치울까.","JPN":"やめちゃおうか。","ENG":"Should I just quit?","TWN":"我不幹了啦！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……때려치우긴 무슨.","JPN":"……やめられるわけないよね。","ENG":"Yeah, like I’ll be able to do that...","TWN":"怎麼可能不幹……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"지원팀 막내만 봐도 쪼다처럼 눈 깔 거면서.","JPN":"応援班の下っ端にもビビッて目も合わせられないくせにさ。","ENG":"I can't even look the rookies on the support team in the eyes...","TWN":"我光是看到支援組裡最小咖的，連大氣都不敢吭一聲。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"하아. 이 시간이면 <color=#ffd34c>라스트 헤이븐</color>에서 커스텀 칵테일이나 홀짝이고 있을 땐데.","JPN":"はあ。この時間なら<color=#ffd34c>ラストヘイブン</color>でカスタムカクテルをすすってるはずなんだけどなあ。","ENG":"Ugh... I should be at <color=#ffd34c>Last Haven</color> right about now, sipping on some custom cocktail...","TWN":"哀，這個時間應該要在<color=#ffd34c>最後的天堂</color>喝杯小酒吧？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"손님 한 잔, 나 한 잔. 둘이 치얼스☆ 하면서, 지나가는 예쁜 바니걸들이랑 하이파이브 하고.","JPN":"お客さん一杯、私一杯。二人で「チアーズ☆」しながら、通り過ぎるキレイなバニーガールズとハイタッチして。","ENG":"One for me, and one for the customer. Cheers☆ Maybe do a high-five with one of the pretty bunny girls...","TWN":"客人一杯，我一杯，彼此乾杯，然後跟穿梭的兔女郎擊掌。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"덩치들 끌고 나타난 우리 헤이븐 형님 얼굴 먼 발치에서 힐끔거리고.","JPN":"ゴロツキをつれて現れたうちのヘイブン兄貴の顔を遠くからちらちら見て。","ENG":"Also, I might even get to see Mr. Haven with his entourage from afar...","TWN":"接著天堂大哥帶著小弟們出現，當我用崇拜的眼神看他時，"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L30_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그때 나랑 눈 마주친 헤이븐 형님이 내 쪽으로 성큼성큼 다가와서 <color=#ffd34c> 네가 소문의 그 신입이냐</color>하고 물으시면……","JPN":"その時、目が合ったヘイブン兄貴が私の方へつかつかと歩いてきて、<color=#ffd34c>お前が噂の新入りか？</color>って聞くと……","ENG":"And Boss who locks his eyes with me walks towards me and says, <color=#ffd34c>\\"So, you’re the new rookie, eh?\\"</color>","TWN":"他也正好和我對上眼，於是他走向我開口問，<color=#ffd34c>你就是傳聞中的那個新人嗎</color>……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"내가 영롱한 목소리로 <color=#ffd34c>네. 뵙고 싶었습니다, 헤이븐 님.</color> 이러면서","JPN":"私が澄んだ声で<color=#ffd34c>はい。お会いしたかったです、ヘイブン様。</color>なーんて言って","ENG":"Then I’ll say with my charming voice, <color=#ffd34c>\\"Yes, Haven, sir. It’s an honor to meet you.\\"</color>","TWN":"我用甜美的聲音回答說，<color=#ffd34c>是的，天堂大哥，久仰大名</color>，"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":" 칵테일 치얼스☆ 한 번 더 하고 바로 비서 취임 따악! 되는 거였는데!","JPN":"もっかいカクテルを「チアーズ☆」して、その場で秘書就職決定！　……ってなるはずだったのに！","ENG":"Cheers☆. We’ll cling our glasses together, and just like that! I’ll be appointed as his secretary!","TWN":"之後我們就又再乾一杯，然後我就坐上秘書的位置！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L34_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"<color=#ffd34c>위저드</color>에 배정시킨 것도 모자라서 이딴 잡무나 시켜?","JPN":"<color=#ffd34c>ウィザード</color>に配属した挙句にこんな雑用だぁ？","ENG":"It’s bad enough being placed in <color=#ffd34c>Wizard</color>, but now they make me do all the grunt work?","TWN":"是<color=#ffd34c>魔法師</color>安排的就算了，還安排這種打雜的爛缺給我？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그것도 이 야밤까지 야근할 만큼 어마어마하게 많은 일을?!","JPN":"しかもこんな夜中まで残業するほどのめちゃくちゃな仕事を！？","ENG":"Not just that, but just look at the amount they dumped on me!!","TWN":"然後事情還多到必須加班？！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"헤이븐 형님은 자기 부하들 인재 보는 눈이 민들레 홀씨만큼도 없다는 걸 아시려나. 이거 말씀드려야 하는 거 아냐?","JPN":"ヘイブン兄貴は自分の部下に人を見る目がこれっぽちもないってこと知ってるのかなあ。これって言うべきじゃない？","ENG":"Is Mr. Haven aware that his advisors can't recognize talent even when it's right in front of their faces? Should I go tell him?","TWN":"天堂大哥知道他的小弟這麼沒有看人的眼光嗎？我是不是應該跟他打小報告？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"<color=#ffd34c>여기</color> 졸업하고, 드디어 헤이븐 형님의 용모를 보나 했는데.","JPN":"<color=#ffd34c>ここ</color>を卒業して、やっとヘイブン兄貴のお顔を拝めると思ったのに。","ENG":"Ugh, I thought I’d finally be able to see Mr. Haven after graduating <color=#ffd34c>here</color>.","TWN":"我還以為從<color=#ffd34c>這裡</color>畢業後，就可以親眼見到天堂大哥的尊容，"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"내 꿈…… 내 환상 돌려줘…….","JPN":"私の夢……私のロマンを返して……","ENG":"Give back my dream... My fantasy...","TWN":"把我的夢想……跟我的幻想還來……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"네에. 저 열심히 일하는 중이었는데, 무슨 일이시…….","JPN":"はーい。一生懸命働いてますけど、なんのご用で……","ENG":"Yes, I’m working real hard here. How can I hel─","TWN":"請進，我正忙著處理事情，請問有什麼事……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L44_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……?","JPN":"……？","ENG":"...?","TWN":"……？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"어…… 얘. 너 여기 오면 안 될 텐데……?","JPN":"え……っと。アンタ、ここに来ちゃダメ……だぞ？","ENG":"Um... Hey, you’re not supposed to be here.","TWN":"呃……小朋友，你不可以來這裡喔……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"……왜?","JPN":"……なんで？","ENG":"...Why?","TWN":"……為什麼？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그야 여긴 애들은 들어오면 안 되는 곳이니까?","JPN":"なんでって、そりゃあここは子どもが入っちゃいけないところだから？","ENG":"Well, that’s because this isn’t a place for kids?","TWN":"沒有為什麼，總之這裡小朋友不能進來！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"딱 봐도 알 만한 차림새네. 악몽을 꾼 거지?","JPN":"その恰好、見ればわかるよ。悪夢を見たんだね？","ENG":"Oh, I get it. You had a nightmare, didn’t you?","TWN":"看你這身穿著，是做惡夢嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"너, 신참이야?","JPN":"アンタ、新入り？","ENG":"Are you new here?","TWN":"你是新來的嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"으응……?","JPN":"ううん……？","ENG":"...Hmm?","TWN":"嗯……？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"되도록이면 빨리 익숙해지는 게 좋을 거야.","JPN":"なるべく早く慣れた方がいいよ。","ENG":"Better get used to it. The nightmares, I mean.","TWN":"我勸你要早點習慣這裡的生活。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"여기 <color=#ffd34c>위저드</color>에선 악몽을 안 꾸는 애가 없거든. 앓는 소리도 못 낸다는 얘기지.","JPN":"ここ、<color=#ffd34c>ウィザード</color>では悪夢を見ない子なんていないんだから。弱音も吐けないってこと。","ENG":"You see, everyone at <color=#ffd34c>Wizard</color> has nightmares. So no use complaining, okay?","TWN":"在<color=#ffd34c>魔法師</color>這裡，沒有一個孩子不做惡夢的，而且是連聲音都喊不出來的程度喔！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"……미안.","JPN":"……ごめん。","ENG":"...Sorry.","TWN":"……對不起。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아니, 뭘 또 사과까지 하고 그래. 사람 무안하게.","JPN":"いや、謝らなくても。気まずいじゃん。","ENG":"It’s okay. There’s no need to apologize to me, though...","TWN":"你幹嘛跟我道歉啦，搞得我像壞人一樣。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이제 그만 떠들고 가. 이러다 너 없어진 거 알면 여기 다 뒤집어지니까.","JPN":"もういいから行きな。アンタがいなくなったことバレたら、ここ全体が騒がしくなるし。","ENG":"You should probably head back. If they notice you're gone, this place will go on high alert to find you.","TWN":"你不要再繼續亂晃，趕快回去。要是被人發現你不在，他們可是會掀了這裡的。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이젠 <color=#ffd34c>오즈</color> 녀석들도 없어서, 엄한 애들이나 쥐 잡듯 잡힐 거라고.","JPN":"もう<color=#ffd34c>オズ</color>の奴らもいないから、何もやってなくてもめっちゃ叱られるよ。","ENG":"Ever since <color=#ffd34c>OZ</color> left, they’re beating kids who misbehave.","TWN":"現在<color=#ffd34c>奧茲國</color>的傢伙又不在，當心你被當成出氣包！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"무서우면 방까지 데려다 줄……","JPN":"怖かったら部屋まで連れてってあげ……","ENG":"If you’re scared, I can help you to your roo─","TWN":"知道怕的話，我帶你回房……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……야! 사람 말하는데 어디 가?! 그쪽 문으로 가면 안 되거든?","JPN":"……おい！　人が話してるのにどこ行くんだよ！？　そっちの扉には入っちゃダメ！","ENG":"H-hey! Where are you going?! You’re not supposed to go that way!","TWN":"……喂！我話都還沒說完你要跑去哪裡？！那道門不能靠近啦！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"저게 무서운 줄 모르고……!","JPN":"あのバカが……！","ENG":"Ugh... Kids these days are fearless...!","TWN":"你這不知天高地厚的小鬼……！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};